using System.Collections.ObjectModel;using NQueen.Domain.Settings;namespace NQueen.Benchmarking;// Goal: Isolate incremental overhead layers that the GUI adds compared to the Console app.// Layers modelled://  1) Baseline: pure solver (no handlers) -> comparable to Console scenario.//  2) SimpleHandlers: attach lightweight counters to events (already close to existing benchmark AttachEventHandlers=true)//  3) GuiLikeHandlers: approximate MainViewModel work://        - Build partial queen placement depth (like OnQueenPlaced)//        - Create Solution objects and add to an ObservableCollection with cap check//        - Perform small dispatcher-like delegate invocation (direct call here)// This is a synthetic approximation (no real WPF / dispatcher marshalling) but captures// allocation + per?event logic cost to quantify relative overhead.[MemoryDiagnoser][CPUUsageDiagnoser]public class SolverEventOverheadBenchmarks{    [Params(8, 10)]    public int BoardSize;    // Focusing on Unique mode (heavier pruning logic, representative for user scenario).    [Params(SolutionMode.Unique)]    public SolutionMode SolutionMode;    // Visualize triggers QueenPlaced events (Hide would suppress most of them in GUI).    [Params(DisplayMode.Visualize)]    public DisplayMode DisplayMode;    [Params(OverheadScenario.Baseline, OverheadScenario.SimpleHandlers, OverheadScenario.GuiLikeHandlers)]    public OverheadScenario Scenario;    private ISolutionFormatter _formatter = new DefaultSolutionFormatter();    // State used only for GuiLikeHandlers scenario    private ObservableCollection<Solution>? _solutionsOc;    private int _queenPlacedCounter;    private int _progressCounter;    [GlobalSetup]    public void Setup()    {        _solutionsOc = new();        _queenPlacedCounter = 0;        _progressCounter = 0;    }    [Benchmark]    public SimulationResults Solve()    {        var solver = new BitmaskSolverExtended(BoardSize, SolutionMode, DisplayMode, _formatter);        solver.DelayInMillisec = 0; // no artificial delay        switch (Scenario)        {            case OverheadScenario.Baseline:                // No subscriptions                break;            case OverheadScenario.SimpleHandlers:                solver.QueenPlaced += (_, _) => _queenPlacedCounter++;                solver.SolutionFound += (_, _) => { /* minimal */ };                solver.ProgressValueChanged += (_, _) => _progressCounter++;                break;            case OverheadScenario.GuiLikeHandlers:                var cap = SimulationSettings.MaxNoOfSolutionsInOutput;                solver.QueenPlaced += (_, e) =>                {                    // Approximate conflict depth calculation from MainViewModel.OnQueenPlaced                    var span = e.Solution.Span;                    int max = Math.Min(BoardSize, span.Length);                    int depth = 0;                    for (int col = 0; col < max; col++)                    {                        int row = span[col];                        if (row < 0) break;                        bool conflict = false;                        for (int prev = 0; prev < col; prev++)                        {                            int prow = span[prev];                            if (prow == row || Math.Abs(prow - row) == col - prev)                            { conflict = true; break; }                        }                        if (conflict) break;                        depth = col + 1;                    }                    _queenPlacedCounter += depth; // accumulate some work so JIT cannot elide                };                solver.SolutionFound += (_, e) =>                {                    if (_solutionsOc == null) return;                    int nextId = _solutionsOc.Count + 1;                    if (cap > 0 && _solutionsOc.Count >= cap) return;                                        // Defer formatting: pass null formatter,
                    // generate Details only for first solution                    var sol = new Solution(e.Solution.ToArray(), _formatter, nextId);                    _solutionsOc.Add(sol);                };                solver.ProgressValueChanged += (_, _) => _progressCounter++;                break;        }        var results = solver.Solve();        // Simple guard so counters are used        if (_queenPlacedCounter < -1) throw new InvalidOperationException();        return results;    }    public enum OverheadScenario    {        Baseline,        SimpleHandlers,        GuiLikeHandlers    }}